import React, { useEffect } from 'react';
import "aos/dist/aos.css";
import AOS from "aos";

const Resume = () => {
  useEffect(() => {
    AOS.init({ duration: 1200, easing: "ease-out-back", once: true });
  }, []);

  return (
    <section id="resume" className="resume section">
      <div className="container section-title" data-aos="fade-up">
        <h2 className="text-gradient fw-900" style={{ fontSize: '3.5rem' }}>The Journey</h2>
        <p className="section-subtitle">A chronological record of professional growth and academic excellence.</p>
      </div>

      <div className="container">
        <div className="row g-5">
          {/* Education Column */}
          <div className="col-lg-6" data-aos="fade-up" data-aos-delay="100">
            <h3 className="text-white mb-5 d-flex align-items-center" style={{ fontSize: '2rem' }}>
              <i className="bi bi-mortarboard text-primary me-3"></i>Academic Foundation
            </h3>

            <div className="resume-timeline-v2">
              {[
                { title: "Bachelor of Engineering", date: "2015 - 2018", desc: "Computer Science & Engineering", inst: "Government College of Engineering, Erode" },
                { title: "Diploma", date: "2012 - 2015", desc: "Computer Science & Engineering", inst: "Valivalam Desikar Polytechnic College, Nagapattinam" },
                { title: "10th Grade", date: "Completed in 2012", desc: "General Academic", inst: "Government Higher Secondary School, Peralam" }
              ].map((item, i) => (
                <div key={i} className="resume-item glass-v2 mb-4 p-5 position-relative" style={{ borderLeft: '4px solid var(--primary)', borderRadius: '0 24px 24px 0' }}>
                  <h4 className="text-gradient fw-bold mb-2">{item.title}</h4>
                  <span className="badge text-primary bg-primary mb-3" style={{ background: 'rgba(59,130,246,0.1)', padding: '8px 16px', borderRadius: '12px' }}>{item.date}</span>
                  <p className="text-white fw-bold mb-1">{item.desc}</p>
                  <p className="text-muted small mb-0"><em>{item.inst}</em></p>
                </div>
              ))}
            </div>
          </div>

          {/* Professional Experience Column */}
          <div className="col-lg-6" data-aos="fade-up" data-aos-delay="200">
            <h3 className="text-white mb-5 d-flex align-items-center" style={{ fontSize: '2rem' }}>
              <i className="bi bi-briefcase text-secondary me-3"></i>Professional Career
            </h3>

            <div className="resume-timeline-v2">
              {[
                { 
                  title: "Senior Software Developer", 
                  date: "Jan 2023 - Present", 
                  inst: "Brandcrock India Pvt. Ltd, Chennai",
                  points: [
                    "Engineered complex Shopware 6 ecosystems with custom API integrations.",
                    "Architected CRM monitoring and POS systems using Node.js & Odoo 17."
                  ]
                },
                { 
                  title: "Software Developer", 
                  date: "Oct 2021 - Dec 2022", 
                  inst: "Novalnet e-Solutions Pvt Ltd, Chennai",
                  points: [
                    "Developed specialized Shopware 5 modules for global payment processing.",
                    "Resolved critical enterprise-level bugs and optimized database performance."
                  ]
                },
                { 
                  title: "Software Developer", 
                  date: "Jul 2018 - Oct 2021", 
                  inst: "Apple G Web Technology Pvt Ltd, Chennai",
                  points: [
                    "Implemented tailored CMS and ERP systems for manufacturing clients.",
                    "Optimized core application logic and managed production deployments."
                  ]
                }
              ].map((item, i) => (
                <div key={i} className="resume-item glass-v2 mb-4 p-5 position-relative" style={{ borderLeft: '4px solid var(--secondary)', borderRadius: '0 24px 24px 0' }}>
                  <h4 className="text-gradient fw-bold mb-2">{item.title}</h4>
                  <span className="badge text-secondary mb-3" style={{ background: 'rgba(139,92,246,0.1)', padding: '8px 16px', borderRadius: '12px', border: '1px solid rgba(139,92,246,0.2)' }}>{item.date}</span>
                  <p className="text-white fw-bold mb-2"><em>{item.inst}</em></p>
                  <ul className="list-unstyled mb-0">
                     {item.points.map((p, pIdx) => (
                       <li key={pIdx} className="text-white small mb-2 opacity-90"><i className="bi bi-check2-circle text-primary me-2"></i>{p}</li>
                     ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Resume;
